const wb = $('Webhook_Multipart').first();
const body = wb.json.body || wb.json;
const full = $('Set_Config_Provisorio').first().json || {};
const skip = new Set(['headers', 'params', 'query', 'body', 'webhookUrl', 'executionMode']);
const cfg = {};
for (const [k, v] of Object.entries(full)) {
  if (!skip.has(k)) cfg[k] = v;
}
const b = wb.binary || {};
const keys = Object.keys(b);
if (!keys.length) {
  throw new Error('No hay archivos binarios. El nodo Set no reenvía binario: se lee de Webhook_Multipart. Enviá multipart con el campo "images" (uno o más) o ejecutá desde el webhook con archivo.');
}
const user_notes = body.user_notes || body.notes || '';
const batch_id = body.batch_id || $execution.id;
return keys.map((key, index) => ({
  json: {
    ...cfg,
    batch_id,
    user_notes: String(user_notes),
    filename: b[key].fileName || `ticket_${index}.jpg`,
    binaryKey: key,
  },
  binary: { image: b[key] },
}));

const orig = $('SplitOut_UnItemPorImagen').all();
const uploaded = $input.all();
if (!orig.length) throw new Error('No hay ítems originales');
if (uploaded.length !== orig.length) {
  throw new Error(`Drive devolvió ${uploaded.length} ítems, se esperaban ${orig.length}`);
}

const drive_items = uploaded.map((u, idx) => {
  const j = u.json || {};
  return {
    index: idx,
    drive_id: j.id,
    drive_web_view_link: j.webViewLink || j.webContentLink || '',
    filename: orig[idx]?.json?.filename,
  };
});

function mpField(boundary, name, value) {
  const head = Buffer.from(
    `--${boundary}\r\nContent-Disposition: form-data; name="${name}"\r\n\r\n`,
    'utf-8',
  );
  return Buffer.concat([head, Buffer.from(String(value), 'utf-8'), Buffer.from('\r\n', 'utf-8')]);
}

function mpFilePart(boundary, fieldName, filename, buf, mimeType) {
  const safeName = (String(filename || 'file').replace(/"/g, '_').replace(/[^\w.\-]/g, '_').replace(/_+/g, '_').slice(0, 200) || 'upload');
  const mime = mimeType || 'application/octet-stream';
  const header = Buffer.from(
    `--${boundary}\r\nContent-Disposition: form-data; name="${fieldName}"; filename="${safeName}"\r\nContent-Type: ${mime}\r\n\r\n`,
    'utf-8',
  );
  return Buffer.concat([header, buf, Buffer.from('\r\n', 'utf-8')]);
}

const batch_id = String(orig[0].json.batch_id || $execution.id);
const un = orig[0].json.user_notes || '';
const boundary = 'n8n_' + Math.random().toString(36).slice(2) + '_' + Date.now();

const parts = [];
parts.push(mpField(boundary, 'batch_id', batch_id));
if (un) parts.push(mpField(boundary, 'user_notes', String(un)));
parts.push(mpField(boundary, 'drive_links_json', JSON.stringify(drive_items.map((d) => String(d.drive_web_view_link || d.drive_webContentLink || '')))));

for (let i = 0; i < orig.length; i++) {
  const it = orig[i];
  const bin = it.binary?.image;
  let buf;
  if (bin && bin.data) {
    buf = Buffer.from(bin.data, 'base64');
  } else if (this.helpers.getBinaryDataBuffer) {
    buf = await this.helpers.getBinaryDataBuffer(i, 'image');
  } else {
    throw new Error('No se pudo leer el binario');
  }
  const fn = it.json.filename || `ticket_${i}.bin`;
  const mime = bin?.mimeType || bin?.fileType || 'application/octet-stream';
  parts.push(mpFilePart(boundary, 'images', fn, buf, mime));
}

parts.push(Buffer.from(`--${boundary}--\r\n`, 'utf-8'));
const body = Buffer.concat(parts);

let base = String(orig[0].json.cloud_run_base || '').trim();
while (base.endsWith('/')) base = base.slice(0, -1);
if (!base) throw new Error('Falta cloud_run_base (nodo Set_Config_Provisorio)');
const url = `${base}/process-batch`;
const secret = String(orig[0].json.x_autodoc_secret || '');
if (!secret) throw new Error('Falta x_autodoc_secret (nodo Set_Config_Provisorio)');

let lastErr;
let parsed;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: {
        'Content-Type': `multipart/form-data; boundary=${boundary}`,
        'X-Autodoc-Secret': secret,
      },
      body,
      timeout: 180000,
    });
    parsed = typeof res === 'string' ? JSON.parse(res) : res;
    lastErr = null;
    break;
  } catch (e) {
    lastErr = e;
    if (attempt < 3) await new Promise((r) => setTimeout(r, 2000 * attempt));
  }
}
if (lastErr) throw lastErr;

return [{
  json: {
    batch_http: parsed,
    drive_items,
    ticket_count: orig.length,
  },
}];

const batch = $input.first().json;
const cfg = $('Set_Config_Provisorio').first().json;
let base = String(cfg.cloud_run_base || '').trim();
while (base.endsWith('/')) base = base.slice(0, -1);
const secret = String(cfg.x_autodoc_secret || '');
const api = batch.batch_http;
if (!api) throw new Error('batch_http ausente');

const detalles = [];
for (const r of api.results || []) {
  if (!r.success || !r.sheets_rows || !r.sheets_rows.length) continue;
  const row = r.sheets_rows[0];
  const d = row.Detalle || row.detalle || '';
  if (d) detalles.push(String(d));
}
const combined = detalles.join(' | ').slice(0, 12000);

let ethics_report = { detalle_empty: true, needs_review: false, max_similarity: 0, threshold: 0, note: 'Sin detalles para comparar' };
try {
  if (combined.trim()) {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: `${base}/ethics-rag`,
      headers: {
        'Content-Type': 'application/json',
        'X-Autodoc-Secret': secret,
      },
      body: JSON.stringify({ detalle: combined }),
      timeout: 120000,
    });
    ethics_report = typeof res === 'string' ? JSON.parse(res) : res;
  }
} catch (e) {
  ethics_report = { needs_review: false, max_similarity: 0, ethics_error: String(e.message || e), note: 'Fallo llamada ethics-rag (se continúa el flujo)' };
}

return [{ json: { batch_http: api, drive_items: batch.drive_items, ticket_count: batch.ticket_count, ethics_report } }];

const root = $input.first().json;
const api = root.batch_http;
const driveByIndex = {};
for (const d of root.drive_items || []) driveByIndex[d.index] = d;
if (!api || !Array.isArray(api.results)) return [{ json: { Error: 'sin results', raw: root } }];
const out = [];
for (const r of api.results) {
  const link = driveByIndex[r.index]?.drive_web_view_link || '';
  const id = driveByIndex[r.index]?.drive_id || '';
  if (!r.success) {
    out.push({
      json: {
        Batch_Id: api.batch_id,
        Source_File: r.filename,
        Drive_File_Id: id,
        Drive_Link: link,
        Error: r.error || '',
        Detail: r.detail || '',
      },
    });
    continue;
  }
  for (const row of r.sheets_rows || []) {
    out.push({
      json: {
        ...row,
        Batch_Id: api.batch_id,
        Source_File: r.filename,
        Drive_File_Id: id,
        Drive_Link: link,
      },
    });
  }
}
return out.length ? out : [{ json: { Batch_Id: api.batch_id, Note: 'sin filas' } }];

const waitItem = $input.first().json;
const b = $('Code_Ethics_RAG').first().json;
const api = b.batch_http;
const ethics = b.ethics_report || {};
const tasks = api.curation_tasks || [];
let links = '';
for (const t of tasks) {
  links += '<li><a href="' + String(t.curation_url || '').replace(/"/g, '') + '">' + String(t.filename || '') + '</a></li>';
}
const resumeUrl = waitItem.resumeUrl || waitItem.executionResumeUrl || '';
const ethLine = ethics.needs_review
  ? '<p style="color:#b45309"><strong>Ética (embeddings vs manual):</strong> Revisar — similitud máx. ' + ethics.max_similarity + '</p>'
  : '<p><strong>Ética:</strong> Sin alerta por similitud con el manual.</p>';
const html = '<html><body style="font-family:system-ui,sans-serif;max-width:640px"><h2>Rendiciones — aprobación de lote</h2><p><strong>Tickets:</strong> ' + b.ticket_count + '</p><p><strong>Batch ID:</strong> ' + api.batch_id + '</p><p><strong>Procesados OK:</strong> ' + (api.results || []).filter((r) => r.success).length + ' / ' + (api.results || []).length + '</p>' + ethLine + '<p><strong>Curación (validar extracción IA):</strong></p><ul>' + (links || '<li>(sin enlaces)</li>') + '</ul><p style="margin-top:20px"><a href="' + resumeUrl + '?decision=approve" style="display:inline-block;padding:10px 16px;background:#0f766e;color:#fff;border-radius:8px;text-decoration:none;margin-right:12px">Aprobar lote</a><a href="' + resumeUrl + '?decision=reject" style="display:inline-block;padding:10px 16px;background:#b91c1c;color:#fff;border-radius:8px;text-decoration:none">Rechazar lote</a></p></body></html>';
return [{ json: { email_html: html } }];
